INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('676ff69222b2c19c', 'LA', '["state","parish","municipal","judicial","special_district"]', 'ballot_access', 'How does the Louisiana open primary system work for state offices?', '["What is a jungle primary?","Do Republicans run against Democrats in the primary?","Louisiana majority vote rule"]', 'For state and parish offices, Louisiana uses an open ''jungle'' primary where all candidates, regardless of party, appear on the same ballot. If one candidate receives a majority (50% plus one vote) in the primary, they are elected outright and do not advance to a general election.', 'https://www.sos.la.gov/ElectionsAndVoting/GetElectionInformation/ReviewTypesOfElections/Pages/default.aspx', 'Louisiana Secretary of State – Types of Elections', '2026-05-09', 'static', 'official_source_direct', 'Applies to all state, parish, and municipal elections.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('56a2dabafbc9ca70', 'LA', '["federal"]', 'ballot_access', 'Do federal elections use the same jungle primary as state elections?', '["Are US House races closed primaries?","Did Louisiana change the congressional primary system?","2026 federal primary rules"]', 'No. Beginning with the 2026 cycle (per Act 1 of 2024 1st Ex. Sess.), Louisiana utilizes a closed partisan primary system for U.S. House and U.S. Senate races. Voters must be registered with a party to vote in its primary, unless the party explicitly opts to open it to unaffiliated voters.', 'https://www.legis.la.gov/legis/ViewDocument.aspx?d=1348680', 'Louisiana State Legislature – Act 1 of 2024 First Extraordinary Session', '2026-05-09', 'static', 'statute_citation', 'Applies exclusively to candidates for U.S. Congress, State Supreme Court, BESE, and PSC.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('6dba88ef9307da0f', 'LA', '["federal","state"]', 'redistricting', 'What congressional map is being used for the 2026 elections?', '["Did the Supreme Court strike down the Louisiana map?","Status of CD5 and CD6 lines","Callais redistricting ruling"]', 'Following the U.S. Supreme Court''s April 29, 2026 ruling in Louisiana v. Callais, the SB 8 remedial map was struck down. The state is currently awaiting a final restored map which will heavily impact the boundaries and partisan leans of CD5 and CD6.', 'https://ballotpedia.org/Redistricting_in_Louisiana_after_the_2020_census', 'Ballotpedia – Redistricting in Louisiana (Callais Tracker)', '2026-05-09', 'volatile', 'secondary_source', 'Applies to all candidates and voters in Louisiana Congressional districts.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7854f8784a5d0e65', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 General Election in Louisiana?', '["What date is the November election?","Congressional General Election date","When is the fall election?"]', 'The 2026 General Election (historically referred to as the Congressional General Election or Open General Election) will be held on Tuesday, November 3, 2026.', 'https://www.sos.la.gov/ElectionsAndVoting/GetElectionInformation/Pages/default.aspx', 'Louisiana Secretary of State – Election Information', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all voters and candidates on the fall ballot.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('082540aec9f1b04d', 'LA', '["federal","state"]', 'election_dates', 'When is the 2026 primary election for Congress and State offices?', '["Did the primary date change due to the lawsuit?","Suspended primary in Louisiana","When is the jungle primary in 2026?"]', 'Due to the ongoing Callais redistricting litigation, early 2026 primary dates were suspended. The state is currently anticipating a rescheduled primary in late Summer (July/August) 2026, pending final legislative and court authorization.', 'https://ballotpedia.org/Elections_in_Louisiana,_2026', 'Ballotpedia – 2026 Louisiana Elections', '2026-05-09', 'volatile', 'secondary_source', 'Applies to all candidates affected by the 2026 election calendar suspension.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('dcb2f71a6e059665', 'LA', '["state"]', 'finance_ethics', 'What is the individual contribution limit for a statewide candidate?', '["How much can someone donate to a Governor race?","Major office contribution cap","Maximum check for statewide campaign"]', 'For a ''major office'' (which includes Governor, Attorney General, and other statewide seats), an individual or regular PAC may contribute a maximum of $5,000 per election.', 'http://ethics.la.gov/Pub/CampFinan/CampFinLimits.pdf', 'Louisiana Board of Ethics – Campaign Finance Limits', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates for statewide ''major offices''.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7ff36cb501be6666', 'LA', '["state"]', 'finance_ethics', 'What is the individual contribution limit for a State Senate or State House candidate?', '["How much can someone donate to a state rep?","District office contribution cap","Max donation for Louisiana legislature"]', 'For a ''district office'' (which includes the State Legislature), the contribution limit from an individual or a regular PAC is $2,500 per election.', 'http://ethics.la.gov/Pub/CampFinan/CampFinLimits.pdf', 'Louisiana Board of Ethics – Campaign Finance Limits', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates for legislative ''district offices''.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('2ffe10b584c9f5bc', 'LA', '["parish","municipal","special_district"]', 'finance_ethics', 'What is the individual contribution limit for a parish or local office?', '["How much can someone donate to a Police Jury race?","Local office contribution cap","Max donation for mayor"]', 'For ''other offices'' (which includes parish, municipal, or ward offices), the contribution limit from any individual or regular PAC is $1,000 per election.', 'http://ethics.la.gov/Pub/CampFinan/CampFinLimits.pdf', 'Louisiana Board of Ethics – Campaign Finance Limits', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates for local/parish ''other offices''.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('cb790e830fad1c78', 'LA', '["state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can a corporation or LLC donate directly to my campaign in Louisiana?', '["Are corporate contributions legal?","Can a business write a campaign check?","LLC donation rules"]', 'Yes. In Louisiana, corporate contributions are legal. Corporations and LLCs are treated as individuals and are subject to the same tiered contribution limits ($5,000 / $2,500 / $1,000) per election.', 'http://ethics.la.gov/Pub/CampFinan/CampFinLimits.pdf', 'Louisiana Board of Ethics – Campaign Finance Limits', '2026-05-09', 'static', 'official_source_direct', 'Applies to state and local candidates accepting business funds.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('ae60464222ea590f', 'LA', '["state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can a PAC give more money to my campaign than an individual donor?', '["Are PAC limits higher than individual limits?","Big PAC contribution rules","How much can a committee give?"]', 'Only if it qualifies as a ''Big PAC'' (a committee with over 250 members that contributes to at least 5 candidates). Big PAC limits are exactly double the standard limits ($10,000 / $5,000 / $2,000). Regular PACs face standard individual limits.', 'http://ethics.la.gov/Pub/CampFinan/CampFinLimits.pdf', 'Louisiana Board of Ethics – Campaign Finance Limits', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all candidates accepting PAC money.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('97fc5ad586d37c41', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'How much cash can a person donate to my campaign?', '["Cash contribution limits","Can someone hand me a $500 bill?","Is it legal to accept physical cash?"]', 'A candidate may not receive cash (currency) contributions in excess of $100 per election from a single contributor. Any contribution exceeding $100 must be made by a written instrument (check, credit card).', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all campaigns.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('6b0f8d9e61413f35', 'LA', '["federal"]', 'ballot_access', 'What is the filing fee for a U.S. Representative in Louisiana?', '["How much to run for US House?","Congressional qualifying fee","Fee for federal office"]', 'The statutory qualifying fee for a candidate for U.S. Representative in Louisiana is $600.', 'https://www.sos.la.gov/ElectionsAndVoting/PublishedDocuments/QualifyingFees.pdf', 'Louisiana Secretary of State – Qualifying Fees', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates for the U.S. House of Representatives.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7fdd5020285cd51c', 'LA', '["federal"]', 'ballot_access', 'What is the filing fee for a U.S. Senator in Louisiana?', '["How much to run for US Senate?","Senate qualifying fee","Federal statewide filing fee"]', 'The statutory qualifying fee for a candidate for U.S. Senator in Louisiana is $600.', 'https://www.sos.la.gov/ElectionsAndVoting/PublishedDocuments/QualifyingFees.pdf', 'Louisiana Secretary of State – Qualifying Fees', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates for the U.S. Senate.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('19913e0d992b0e48', 'LA', '["state"]', 'ballot_access', 'What is the qualifying fee to run for the State Legislature?', '["How much does it cost to run for State House?","State Senator filing fee","Legislative ballot cost"]', 'The qualifying fee for a candidate for either State Senator or State Representative is $400.', 'https://www.sos.la.gov/ElectionsAndVoting/PublishedDocuments/QualifyingFees.pdf', 'Louisiana Secretary of State – Qualifying Fees', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates for the Louisiana Legislature.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('ad8f69a8321fefe0', 'LA', '["parish"]', 'ballot_access', 'What is the filing fee for a parish office like Police Jury?', '["How much to run for Police Jury?","Parish council filing fee","Local office qualifying costs"]', 'Qualifying fees for parish offices vary significantly based on the specific office and parish population, but they generally range between $115 and $450.', 'https://www.sos.la.gov/ElectionsAndVoting/PublishedDocuments/QualifyingFees.pdf', 'Louisiana Secretary of State – Qualifying Fees', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates for parish-level offices.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('f7ff98507c746289', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'ballot_access', 'Can I qualify for the ballot by petition instead of paying the filing fee?', '["Petition alternative in Louisiana","Do I have to pay if I get signatures?","Signature requirements to avoid fees"]', 'Yes. A candidate may qualify by filing a nominating petition with the required specific number of signatures (e.g., 1,000 for U.S. House, 400 for State Legislature) instead of paying the monetary qualifying fee.', 'https://www.sos.la.gov/ElectionsAndVoting/BecomeACandidate/QualifyForAnElection/Pages/default.aspx', 'Louisiana Secretary of State – Qualify for an Election', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates utilizing the petition method.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('5d086a943f382080', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'ballot_access', 'What official form do I use to file for office?', '["Notice of Candidacy","What paperwork do I need to get on the ballot?","Qualifying forms"]', 'A candidate must file a ''Notice of Candidacy'' form, which must be executed before a notary public, and submitted alongside either the required qualifying fee or certified nominating petition.', 'https://www.sos.la.gov/ElectionsAndVoting/BecomeACandidate/QualifyForAnElection/Pages/default.aspx', 'Louisiana Secretary of State – Qualify for an Election', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates seeking ballot access.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7c0dc363916d0596', 'LA', '["state"]', 'candidate_eligibility', 'How long do I have to live in my district to run for the State Legislature?', '["Residency requirements for State Rep","Domicile rules for state senate","How long must I be a resident?"]', 'Under the Louisiana Constitution, a candidate for the legislature must have been a resident of the state for the two years preceding the election and actually domiciled in the specific legislative district for one year preceding the election.', 'https://senate.la.gov/Documents/Constitution/Article3.htm', 'Louisiana Constitution, Article III, Section 4', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for the Louisiana House and Senate.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('179cb99cf1486a8a', 'LA', '["federal","state"]', 'redistricting', 'If my district was just redrawn, does my residency clock reset?', '["Redistricting impact on domicile","Do new map lines ruin my 1-year residency?","Running in a redrawn district"]', 'No. The Louisiana Constitution provides an exception: if a district is reapportioned, a candidate may qualify in the new district if they were domiciled in the old district that forms part of the new one for the required one-year period.', 'https://senate.la.gov/Documents/Constitution/Article3.htm', 'Louisiana Constitution, Article III, Section 4', '2026-05-09', 'volatile', 'statute_citation', 'Applies to candidates running in districts affected by reapportionment.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('087ffc2d3aa01979', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to officially appoint a campaign treasurer before campaigning?', '["When do I file my treasurer form?","Do I need a treasurer to raise money?","Campaign bank account rules"]', 'Yes. A candidate must designate a campaign treasurer and establish a campaign depository (bank account) before receiving any contributions or making any campaign expenditures. The candidate may serve as their own treasurer.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates raising or spending money.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('6358853818fffc5e', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign bank account have to be located in Louisiana?', '["Can I use an out of state bank?","Campaign depository location rules","Where can I open my campaign account?"]', 'Yes. The campaign depository must be a bank, savings and loan association, or credit union authorized to do business in the state of Louisiana.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all campaign treasurers establishing accounts.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('c9539e5d543ed52f', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late with the Ethics Board?', '["How much are late filing fines?","Ethics board late fees","What happens if I miss a reporting deadline?"]', 'Penalties accrue daily and vary by office tier: $100 per day for major office, $60 per day for district office, and $40 per day for other offices. Fines are capped at the total amount of receipts or expenditures in the specific report, or by specific statutory maximums.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all candidates filing finance disclosures.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7b2157e97222884f', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'ballot_access', 'Can I run as a write-in candidate if I missed the normal qualifying period?', '["Write-in candidate rules","How do I run as a write in?","Are write in votes counted?"]', 'For state and local offices, write-ins are generally banned unless no one qualifies for the office. However, for federal congressional races, you may run as a write-in if you file a formal notice and declaration with the Secretary of State by the statutory deadline.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81432', 'Louisiana Revised Statutes § 18:482', '2026-05-09', 'static', 'statute_citation', 'Applies to individuals attempting ballot access outside normal qualifying.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('2c45a7e76a8cf17f', 'LA', '["state","parish","municipal","judicial"]', 'candidate_eligibility', 'Does Louisiana have a ''resign-to-run'' law?', '["Do I have to quit my job to run for office?","Can I hold two offices at once?","Dual officeholding rules"]', 'Louisiana does not have a blanket ''resign-to-run'' law requiring resignation simply to campaign. However, strict Dual Officeholding laws prevent a person from actually holding certain combinations of federal, state, and local offices simultaneously if elected.', 'https://www.sos.la.gov/ElectionsAndVoting/BecomeACandidate/ReviewQualifications/Pages/default.aspx', 'Louisiana Secretary of State – Review Qualifications', '2026-05-09', 'static', 'official_source_direct', 'Applies to current officeholders seeking a new office.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('1702635c38f30ba1', 'LA', '["state","parish","municipal","special_district"]', 'recall_rules', 'Can a parish official or mayor be recalled from office by voters?', '["Recall elections for local officials","Can we remove a police juror?","Are mayors subject to recall?"]', 'Yes. Louisiana law allows voters to recall any state, district, parish, municipal, or ward officer (with the exception of judges) by circulating a petition that meets statutory signature thresholds based on the jurisdiction''s voting population.', 'https://www.sos.la.gov/ElectionsAndVoting/GetElectionInformation/RecallAnElectedOfficial/Pages/default.aspx', 'Louisiana Secretary of State – Recall an Elected Official', '2026-05-09', 'static', 'official_source_direct', 'Applies to voters initiating a recall and targeted elected officials.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('45e0384f9b4e6f62', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'When is the first campaign finance report due before an election?', '["When do I file my first finance report?","30-day pre-election report","Reporting deadline schedule"]', 'Candidates must file their first pre-election campaign finance report no later than the 30th day prior to the primary election.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates filing finance disclosures.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('3443e6a2493ab1ea', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'What is the final reporting deadline just before election day?', '["10-day pre-election report","When is the last finance report due before voting?","Reporting schedule right before the election"]', 'A second pre-election campaign finance report must be filed no later than the 10th day before both the primary and the general election.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates active on the ballot.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('57ad1564f43e5e02', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to file campaign finance reports in years when I am not running?', '["Annual supplemental reports","Reporting in off years","Do I still report if my campaign is dormant?"]', 'Yes. All candidates and officeholders with open accounts (who have unexpended funds or outstanding debts) must file an Annual Supplemental report by February 15th of each year.', 'https://www.legis.la.gov/legis/Law.aspx?d=81285', 'Louisiana Revised Statutes § 18:1491.6', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates/officeholders with active campaign accounts.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('9887817ca50cb354', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'What happens if I receive a large donation right before the election?', '["48-hour report rules","Late contribution disclosure","Reporting large checks right before voting"]', 'If you receive a contribution over a specific threshold (e.g., $1,000 for statewide, $500 for district, $250 for local) within 20 days of the election, you must file a Special Report within 48 hours of receipt.', 'https://www.legis.la.gov/legis/Law.aspx?d=81287', 'Louisiana Revised Statutes § 18:1491.8', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates receiving late, large contributions.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7e63b374973696d2', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay for my personal living expenses?', '["Personal use of campaign funds","Can I pay rent with donor money?","Impermissible uses of campaign cash"]', 'No. Campaign funds cannot be used for personal use. They are strictly limited to expenses related to a political campaign, the holding of a public office, charitable donations, or transfers to a political party.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('48d078868cd684aa', 'LA', '["state","parish","municipal","judicial"]', 'finance_ethics', 'Do I have to file a Personal Financial Disclosure (PFD) as a candidate?', '["Disclosing my personal income","Tier 1 vs Tier 2 PFD","Filing financial disclosure statements"]', 'Yes. Candidates for offices with an annual salary of $5,000 or more must file a Personal Financial Disclosure statement (Tier 1, 2, or 3 depending on the office''s level of authority) with the Board of Ethics.', 'http://ethics.la.gov/Pub/Laws/CampFinan.pdf', 'Louisiana Board of Ethics – Campaign Finance Act', '2026-05-09', 'static', 'official_source_direct', 'Applies to candidates for salaried state and local offices.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('a19a9d1edbf05d8c', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'How do I report a personal loan made to my own campaign?', '["Lending money to myself","Do personal loans count as contributions?","Funding my own campaign"]', 'A candidate''s loan to their own campaign must be explicitly reported as a loan on the campaign finance report, rather than a standard contribution, ensuring it can be legally repaid with campaign funds later without violating personal use limits.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates self-funding through loans.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('86a3db6839b4fbf1', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'How long do I need to keep my campaign receipts and bank statements?', '["Record retention rules","How long to save financial documents","Campaign bookkeeping requirements"]', 'Campaign treasurers must maintain all records, accounts, and receipts for a period of four years after the date the related campaign finance report is filed.', 'https://www.legis.la.gov/legis/Law.aspx?d=81273', 'Louisiana Revised Statutes § 18:1491.2', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaign treasurers and candidates.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('898d08115316c37f', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'election_dates', 'What is the deadline to register to vote by mail or in person for the 2026 elections?', '["When does paper voter registration close?","Last day to register by mail","In-person voter registration cutoff"]', 'The deadline to register to vote in person at the Registrar of Voters office or by mail is 30 days prior to the election date.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81467', 'Louisiana Revised Statutes § 18:135(A)(1)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all unregistered eligible voters utilizing paper/in-person methods.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('b7d41a73f4619e88', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'election_dates', 'What is the deadline to register to vote online using GeauxVote?', '["Online voter registration deadline","GeauxVote cutoff date","Last day to register on the internet"]', 'The deadline to register to vote online through the Louisiana GeauxVote portal is 20 days prior to the election date.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81467', 'Louisiana Revised Statutes § 18:135(A)(2)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all unregistered eligible voters utilizing the online portal.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('a528497916de7d61', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'What kind of ID does a voter need at the polls in Louisiana?', '["Voter ID requirements","Can I use LA Wallet to vote?","Do voters need a driver''s license?"]', 'Voters must present a Louisiana driver''s license, the LA Wallet app, a Louisiana Special ID card, or a military ID. If they lack a recognized photo ID, they may vote by filling out and signing a voter affidavit.', 'https://www.sos.la.gov/ElectionsAndVoting/Vote/VoteOnElectionDay/Pages/default.aspx', 'Louisiana Secretary of State – Vote on Election Day', '2026-05-09', 'static', 'official_source_direct', 'Applies to all in-person voters.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('17667445490de295', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'What is the deadline to request a mail-in absentee ballot?', '["When is the last day to ask for an absentee ballot?","Deadline for mail ballot request","How late can a voter request to vote by mail?"]', 'A voter must request an absentee by mail ballot no later than 4:30 p.m. on the 4th day before election day (which is the Tuesday before a standard Saturday election).', 'https://www.legis.la.gov/Legis/Law.aspx?d=81395', 'Louisiana Revised Statutes § 18:1307(A)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all eligible absentee voters.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('e5b5466efc82fb3b', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline to return a mail-in absentee ballot?', '["How late can I mail my ballot?","Deadline for the registrar to receive absentee ballots","Mail ballot submission deadline"]', 'Absentee by mail ballots must be received by the Registrar of Voters no later than 4:30 p.m. on the day immediately preceding election day (excluding military and overseas voters).', 'https://www.legis.la.gov/Legis/Law.aspx?d=81396', 'Louisiana Revised Statutes § 18:1308(A)(1)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to domestic absentee voters.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('003a1ed7343d9b6e', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'election_dates', 'When does early voting start and end in Louisiana?', '["What are the early voting dates?","How long is the early voting period?","Early voting window timeline"]', 'Early voting generally begins 14 days prior to an election and ends 7 days prior to the election, running from 8:30 a.m. to 6:00 p.m., explicitly excluding Sundays.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81397', 'Louisiana Revised Statutes § 18:1309(A)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all elections offering early voting.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('192f6c1d65f833b0', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'How far away must campaign volunteers stay from the polling place entrance?', '["Electioneering distance in Louisiana","Can I put signs near the voting building?","The 600-foot rule"]', 'Louisiana law strictly prohibits electioneering, handing out flyers, or placing campaign signs within 600 feet of the entrance to any polling place on election day.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81423', 'Louisiana Revised Statutes § 18:1462(A)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns and electioneers.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('b679cecd979b813e', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'How many poll watchers can my campaign have at a precinct?', '["Can I appoint observers?","Rules for poll watchers","Who can be a commissioner-watcher?"]', 'A candidate is entitled to have one poll watcher (legally referred to as a commissioner-watcher) at every precinct where they appear on the ballot. They must be a registered voter of the parish.', 'https://www.legis.la.gov/legis/Law.aspx?d=81525', 'Louisiana Revised Statutes § 18:427', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns appointing election observers.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('9d7f458775cedba8', 'LA', '["parish","municipal","special_district"]', 'recall_rules', 'How many signatures are needed to recall an official in a large parish (over 100,000 voters)?', '["Recall signature threshold for big cities","Percentage of voters needed for recall","Recall math for large populations"]', 'In voting areas with 100,000 or more registered voters, a recall petition requires valid signatures from at least 20% of the qualified electors in that voting area.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81382', 'Louisiana Revised Statutes § 18:1300.2(B)', '2026-05-09', 'static', 'statute_citation', 'Applies to organizers recalling officials in large jurisdictions.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('398bfbc9214c71d5', 'LA', '["state","parish","municipal","special_district"]', 'recall_rules', 'What is the recall signature threshold for a medium-sized municipality or parish?', '["Recall signatures for 25k-100k voters","How many signatures to recall a mayor?","Recall petition requirements"]', 'For voting areas with 25,000 to 99,999 registered voters, the recall petition must be signed by at least 25% of the qualified electors.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81382', 'Louisiana Revised Statutes § 18:1300.2(B)', '2026-05-09', 'static', 'statute_citation', 'Applies to organizers recalling officials in medium jurisdictions.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('c0b57b734936e302', 'LA', '["state","parish","municipal","special_district"]', 'recall_rules', 'How long do organizers have to collect recall petition signatures?', '["Time limit for a recall","Deadline to submit recall petition","How many days to get recall signatures?"]', 'Organizers have exactly 180 days from the date the recall petition is officially filed with the Secretary of State to collect the required number of signatures and submit them.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81382', 'Louisiana Revised Statutes § 18:1300.2(C)', '2026-05-09', 'static', 'statute_citation', 'Applies to all statutory recall efforts.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('1480d4919936ddfd', 'LA', '["state","parish","municipal","judicial"]', 'runoff_rules', 'What happens if three candidates tie in the jungle primary?', '["Three-way tie in primary","Who advances if the vote is tied?","Tiebreaker for second place runoff spot"]', 'If no candidate receives a majority and there is a tie for the second runoff spot, all tied candidates advance to the general election runoff, resulting in three or more candidates appearing on the runoff ballot.', 'https://www.sos.la.gov/ElectionsAndVoting/GetElectionInformation/ReviewTypesOfElections/Pages/default.aspx', 'Louisiana Secretary of State – Types of Elections', '2026-05-09', 'static', 'official_source_direct', 'Applies to state and local open primary elections.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('a0f6aa2d873aadee', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'runoff_rules', 'Can a candidate who makes the runoff withdraw before the general election?', '["Withdrawing from the runoff","Can I concede before the general election?","Canceling a runoff"]', 'Yes. If a runoff candidate formally withdraws by filing the proper notice with the Secretary of State, the remaining candidate is declared the winner and the runoff election for that office is canceled.', 'https://www.sos.la.gov/ElectionsAndVoting/BecomeACandidate/QualifyForAnElection/Pages/default.aspx', 'Louisiana Secretary of State – Qualify for an Election', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates who advance to a runoff election.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7adffdcdf667ebaa', 'LA', '["state","parish","municipal","judicial"]', 'ballot_access', 'How is the order of candidate names determined on the primary ballot?', '["Ballot order rules","Do incumbents get listed first?","Is the ballot order randomized?"]', 'In Louisiana, candidates for the same office are listed in strict alphabetical order by their last name on the ballot. There is no random drawing or party-preference ordering for the primary.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81488', 'Louisiana Revised Statutes § 18:551', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidate ballot positioning.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('8ebc0ef15a78d238', 'LA', '["state","parish","municipal","judicial"]', 'runoff_rules', 'Does a candidate''s political party matter for advancing to a runoff in a state race?', '["Can two Republicans be in the runoff?","Top-two primary party rules","Do parties limit runoff spots?"]', 'No. Under the open primary system for state/local races, the top two vote-getters advance to the runoff regardless of their party affiliation. It is common to have a runoff between two candidates of the same party.', 'https://www.sos.la.gov/ElectionsAndVoting/GetElectionInformation/ReviewTypesOfElections/Pages/default.aspx', 'Louisiana Secretary of State – Types of Elections', '2026-05-09', 'static', 'official_source_direct', 'Applies to all state and local open primary candidates.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('55ddf0261defdeaa', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to file my campaign finance reports electronically?', '["Electronic filing requirements","Can I submit paper finance reports?","How to submit the disclosure form"]', 'Candidates for statewide offices must file electronically. Candidates for district or local offices may file via paper or electronically, though the Board of Ethics strongly encourages electronic filing.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates filing finance reports.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('90ecae9fdb4f178a', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can my spouse loan money to my campaign?', '["Loans from family members","Can my husband fund my campaign?","Spouse contribution limits"]', 'Yes. A candidate or their spouse may make unlimited loans to the campaign from their personal funds, provided they are properly disclosed as loans on the campaign finance report.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to candidates utilizing personal/spousal funds.', 'batch_2026-05-10T02-10-04_louisiana_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('104c818d0dbf3251', 'LA', '["federal","state"]', 'redistricting', 'What happens to candidates who already filed under the SB 8 map now that it has been struck down by the Callais ruling?', '["Do I have to re-qualify if my district lines changed?","Callais ruling impact on filed candidates","What happens to my qualifying fee if the map is thrown out?"]', 'When a map is struck down and redrawn mid-cycle, the Secretary of State typically reopens the qualifying period for the affected districts. Candidates who already paid filing fees or submitted petitions must file new Notices of Candidacy for the newly drawn districts, but previous fees are generally rolled over or refunded if they no longer reside in the district.', 'https://www.sos.la.gov/ElectionsAndVoting/BecomeACandidate/QualifyForAnElection/Pages/default.aspx', 'Louisiana Secretary of State – Candidate Qualifying', '2026-05-09', 'volatile', 'official_source_direct', 'Applies to congressional candidates affected by mid-cycle redistricting.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('04b509a38fdcc99b', 'LA', '["federal","state"]', 'redistricting', 'Do I have to return campaign contributions if my district boundaries change due to the Callais lawsuit?', '["Redistricting impact on raised funds","Can I keep my money if my district number changes?","Transferring funds between districts"]', 'No. Campaign funds belong to the candidate''s campaign committee, not the specific district. As long as the candidate is running for the same level of office (e.g., U.S. House), they retain all collected funds, though they must still adhere to per-election contribution limits.', 'http://ethics.la.gov/Pub/Laws/CampFinan.pdf', 'Louisiana Board of Ethics – Campaign Finance Act', '2026-05-09', 'static', 'official_source_direct', 'Applies to candidates shifting districts due to reapportionment.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7b05300ec0cff83e', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'ballot_access', 'When is the statutory qualifying period for the 2026 Fall elections?', '["When does qualifying open in 2026?","Dates to file for office","Summer qualifying period timeline"]', 'Due to Act 1 of 2024, qualifying periods are now split. Candidates for the open jungle primary (State/Local) typically qualify the third Wednesday in July (projected July 15-17, 2026). Candidates in the new closed primary (Federal, Supreme Court, BESE, PSC) face a completely different, earlier qualifying schedule depending on the finalized election date, which is highly volatile due to litigation.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81468', 'Louisiana Revised Statutes § 18:467(1)', '2026-05-09', 'volatile', 'statute_citation', 'Applies to all candidates qualifying for the fall ballot.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('0b4479c90a17320e', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'Does an absentee by mail ballot require a witness signature in Louisiana?', '["Do I need a notary for my mail ballot?","Witness requirements for absentee voting","Who can sign my ballot envelope?"]', 'Yes. Louisiana law strictly requires that the voter sign the absentee ballot envelope affidavit in the presence of one witness, who must also sign the envelope, OR it must be signed before a notary public.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81395', 'Louisiana Revised Statutes § 18:1306(E)(2)', '2026-05-09', 'static', 'statute_citation', 'Applies to all voters utilizing absentee by mail voting.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('5a14c424f0bf5eeb', 'LA', '["special_district"]', 'election_dates', 'When can local governments hold special tax or bond elections?', '["Bond election dates","When do tax renewals go on the ballot?","Local proposition election schedule"]', 'Louisiana restricts special tax, bond, and proposition elections to specific, uniform election dates established by the legislature, typically limited to designated Saturdays in the Spring (March/April) and Fall (October/November).', 'https://www.legis.la.gov/Legis/Law.aspx?d=81404', 'Louisiana Revised Statutes § 18:402', '2026-05-09', 'static', 'statute_citation', 'Applies to local governments and campaigns involved in ballot propositions.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('6ab5e78e64074030', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'ballot_access', 'Can I change my party affiliation right before I file to run for office?', '["Switching parties to run","Party registration deadlines for candidates","How long do I have to be in a party to run under their label?"]', 'For races utilizing the closed partisan primary (Federal, BESE, PSC, Supreme Court), Act 1 of 2024 requires a candidate to be registered with the party. However, for the open jungle primary (State/Local), a candidate simply lists their current party affiliation on their Notice of Candidacy at the time of qualifying.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81431', 'Louisiana Revised Statutes § 18:463(A)(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates declaring a party label.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('5f356885bd51db01', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can I falsely claim to be the endorsed candidate of a political party?', '["Anti-bait-and-switch advertising","Lying about party endorsements","Can I put the GOP logo on my signs if they didn''t endorse me?"]', 'No. Under Louisiana''s truth in political advertising laws, it is illegal for a candidate to falsely claim or imply that they are the official nominee or endorsed candidate of a recognized political party if they are not.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81308', 'Louisiana Revised Statutes § 18:1463(C)', '2026-05-09', 'static', 'statute_citation', 'Applies to all political advertising and campaign communications.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('663d92f935af4e60', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'residency', 'Under Louisiana civil law, what is the difference between a ''residence'' and a ''domicile''?', '["Domicile vs residence","Can I have two houses?","Which home counts for my qualifying?"]', 'In Louisiana civil law, a ''residence'' is any place where a person lives, but a ''domicile'' is the principal domestic establishment where a person habitually resides and intends to remain. A person may have multiple residences, but only one legal domicile.', 'https://www.legis.la.gov/Legis/Law.aspx?d=114032', 'Louisiana Civil Code, Article 38', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidate eligibility calculations.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('115593188b90e488', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'residency', 'If I buy a house in my district but haven''t moved in yet, is it my domicile?', '["When does my domicile change?","Intent to change domicile","Establishing residency for qualifying"]', 'No. Under Louisiana civil law, a change in domicile requires two concurrent elements: actual physical residence in the new location AND the clear intent to make it your principal establishment. Owning property alone does not change your domicile.', 'https://www.legis.la.gov/Legis/Law.aspx?d=114034', 'Louisiana Civil Code, Article 41', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates shifting residency prior to elections.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('2dddfa69878cdfa4', 'LA', '["judicial"]', 'ballot_access', 'Do candidates for the Louisiana Supreme Court run in the jungle primary?', '["Supreme court primary rules","Are judicial races closed primaries?","How are supreme court justices elected?"]', 'No. Pursuant to the 2024 Act 1 election overhaul, candidates for the Louisiana Supreme Court now run in a closed, partisan primary system, separating them from lower court judges who remain in the open jungle primary.', 'https://www.legis.la.gov/legis/ViewDocument.aspx?d=1348680', 'Louisiana State Legislature – Act 1 of 2024 First Extraordinary Session', '2026-05-09', 'static', 'statute_citation', 'Applies exclusively to candidates for the State Supreme Court.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('cd0511bd62327066', 'LA', '["judicial"]', 'ballot_access', 'Do candidates for District and Appellate Courts run in the jungle primary?', '["Lower court judge elections","Are district judge races partisan?","Appellate court primary type"]', 'Yes. Unlike the Supreme Court, candidates for District Courts and Courts of Appeal continue to run in Louisiana''s traditional open ''jungle'' primary system.', 'https://www.sos.la.gov/ElectionsAndVoting/GetElectionInformation/ReviewTypesOfElections/Pages/default.aspx', 'Louisiana Secretary of State – Types of Elections', '2026-05-09', 'static', 'official_source_direct', 'Applies to candidates for District and Appellate courts.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('2c1c6da3f9062850', 'LA', '["state"]', 'ballot_access', 'How are candidates for the Board of Elementary and Secondary Education (BESE) elected?', '["BESE primary rules","Are education board races partisan?","BESE election system"]', 'Under the 2024 Act 1 election reforms, candidates for BESE now run in the closed partisan primary system, similar to federal congressional races.', 'https://www.legis.la.gov/legis/ViewDocument.aspx?d=1348680', 'Louisiana State Legislature – Act 1 of 2024 First Extraordinary Session', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for BESE.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('6e5abd339fc5e1c8', 'LA', '["state"]', 'ballot_access', 'How are candidates for the Public Service Commission (PSC) elected?', '["PSC primary rules","Are utility regulators in the jungle primary?","Public Service Commission elections"]', 'Under the 2024 Act 1 election reforms, candidates for the Public Service Commission (PSC) now participate in the closed partisan primary system.', 'https://www.legis.la.gov/legis/ViewDocument.aspx?d=1348680', 'Louisiana State Legislature – Act 1 of 2024 First Extraordinary Session', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for the Public Service Commission.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('d43362882b8adced', 'LA', '["special_district"]', 'ballot_access', 'Are levee district board members elected by the voters?', '["How do I run for the levee board?","Levee commissioner elections","Flood protection authority positions"]', 'Generally, no. The vast majority of levee district commissioners and flood protection authority members in Louisiana are appointed by the Governor, not elected by voters, though specific local nominating committees often supply the candidate lists.', 'https://www.legis.la.gov/Legis/Law.aspx?d=101031', 'Louisiana Revised Statutes § 38:291', '2026-05-09', 'static', 'statute_citation', 'Applies to individuals seeking to serve on Levee/Flood boards.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('08aa8f2fc1ca294a', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Are contribution limits higher if I am challenging an incumbent instead of running for an open seat?', '["Incumbent challenge limits","Do open seats have different financial rules?","Does it cost more to fight an incumbent?"]', 'No. Louisiana campaign finance limits are strictly based on the tier of the office sought (Major, District, or Other) and do not change based on whether the seat is open or occupied by an incumbent.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7e677821fbc9a052', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Are my campaign emails subject to the Louisiana Public Records Act?', '["Can reporters FOIA my campaign emails?","Public Records Act for candidates","Are my campaign texts public?"]', 'While you are merely a candidate, your private campaign communications are not generally subject to the Public Records Act. However, once elected, if you use private email to discuss public business, those specific communications become subject to public disclosure.', 'https://www.legis.la.gov/Legis/Law.aspx?d=99727', 'Louisiana Revised Statutes § 44:1 (Public Records Act)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidate and officeholder communications.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('55ca6eb9e09fcbbb', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'How do I report an in-kind contribution of food or printing services?', '["Reporting donated food","In-kind contribution rules","Valuing free printing"]', 'An in-kind contribution must be reported at its fair market value on your campaign finance report. It is reported simultaneously as both a contribution received and an expenditure made during that reporting period.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all campaigns receiving non-monetary goods/services.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('d1800ae7399c6a40', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Are loans from third parties subject to campaign contribution limits?', '["Can a business loan me $50,000?","Loan limits","Are loans treated as donations?"]', 'Yes. A loan made to a campaign by anyone other than the candidate or the candidate''s spouse is considered a contribution and is strictly subject to the per-election contribution limits for that specific office.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to campaigns receiving outside loans.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('c8151f5a402a5b4d', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'When must my campaign treasurer deposit a contribution into our bank account?', '["Deposit timing rules","How long can I hold a check?","Bank deposit deadlines"]', 'Louisiana law (La. R.S. 18:1491.4) mandates that all contributions be deposited into the designated campaign depository. Unlike other states with strict multi-day countdowns, Louisiana does not statutorily mandate a specific number of days, but the funds must be deposited to accurately reflect on the required reporting periods.', 'https://www.legis.la.gov/legis/Law.aspx?d=81275', 'Louisiana Revised Statutes § 18:1491.4(C)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaign treasurers processing funds.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('84780e6d4c8c592d', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay a traffic ticket I got while driving to a rally?', '["Paying fines with campaign money","Are parking tickets a campaign expense?","Traffic violations during campaigning"]', 'No. The use of campaign funds to pay fines, penalties, or any criminal or civil liabilities—including traffic tickets—is strictly prohibited, even if the infraction occurred while traveling for campaign purposes.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2(I)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates holding campaign funds.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('64617f80c9575728', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can I donate my campaign funds to a charity?', '["Giving campaign money to a 501c3","Charitable donations from political accounts","Donating surplus funds"]', 'Yes, campaign funds may be donated to a tax-exempt charitable organization. However, the donation is prohibited if the candidate, or any member of their immediate family, is employed by or receives compensation from that specific charity.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2(I)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates making charitable donations.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('a02828428b504598', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'What happens if someone leaves an anonymous envelope of cash at my campaign HQ?', '["Anonymous donations","Can I keep unnamed contributions?","Reporting cash drops"]', 'Anonymous contributions are strictly prohibited. Any anonymous contribution received must immediately be escheated (turned over) to the state by remitting it to the Board of Ethics.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2(B)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns receiving untraceable funds.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('fe5f410d3f71c3a8', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can a PAC contribute to my campaign if it isn''t registered in Louisiana?', '["Out-of-state PAC donations","Federal PAC limits","Accepting money from a DC committee"]', 'Yes. An out-of-state or federal PAC can contribute to a Louisiana candidate, provided they adhere to the Louisiana per-election contribution limits. If they are not registered with the LA Ethics Board, they may have separate reporting obligations if their contributions exceed certain thresholds.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to candidates receiving out-of-state funds.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('5d197055c1cc7260', 'LA', '["state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Is it legal to use campaign funds to buy a list of voters?', '["Buying voter data with donor money","Are voter files a campaign expense?","Paying the SOS for data"]', 'Yes. Purchasing voter registration lists from the Secretary of State or a political data vendor is considered a standard, legally permissible campaign expenditure.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns purchasing data.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('f673ffa88f0bcac1', 'LA', '["judicial"]', 'finance_ethics', 'Who oversees campaign finance reports for judicial candidates?', '["Does the Ethics Board handle judges?","Who do judges report their donors to?","Judicial finance oversight"]', 'While judicial conduct is generally overseen by the Judiciary Commission, all judicial candidates are subject to the Campaign Finance Disclosure Act and must file their campaign finance reports with the Louisiana Board of Ethics, identical to non-judicial candidates.', 'http://ethics.la.gov/Pub/CampFinan/CFBrochure.pdf', 'Louisiana Board of Ethics – Campaign Finance Brochure', '2026-05-09', 'static', 'official_source_direct', 'Applies to all judicial candidates.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('dcf348b62271f6bf', 'LA', '["state","parish","municipal","special_district"]', 'recall_rules', 'Do I have to prove a specific crime or violation to initiate a recall against a local official?', '["Recall grounds in Louisiana","What reasons justify a recall election?","Does malfeasance have to be proven to recall?"]', 'No. Unlike some other states that require specific legal grounds (like malfeasance or incompetence), Louisiana law does not require any specific grounds or reasons to be stated or proven in a recall petition.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81381', 'Louisiana Revised Statutes § 18:1300.1', '2026-05-09', 'static', 'statute_citation', 'Applies to all individuals initiating a statutory recall.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('e28f99f938b3add3', 'LA', '["state","parish","municipal","special_district"]', 'recall_rules', 'When is a recall election scheduled if the petition signatures are verified?', '["Timing of recall vote","When does the recall election happen?","Scheduling the recall ballot"]', 'Once the Secretary of State certifies the petition, the governor must issue a proclamation within 15 days ordering an election to be held on the next available statutory election date.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81387', 'Louisiana Revised Statutes § 18:1300.7', '2026-05-09', 'static', 'statute_citation', 'Applies to state and local officials facing certified recall.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('192b0bdc433a198e', 'LA', '["judicial"]', 'finance_ethics', 'Can I personally ask people for campaign donations if I''m running for judge?', '["Judicial fundraising restrictions","Can a judge solicit funds?","Code of Judicial Conduct rules"]', 'No. Under the Louisiana Code of Judicial Conduct (Canon 7), a judge or a judicial candidate may not personally solicit or accept campaign contributions. All fundraising must be handled strictly by a campaign committee.', 'https://www.lasc.org/rules/supreme/cjc.asp', 'Louisiana Supreme Court – Code of Judicial Conduct Canon 7', '2026-05-09', 'static', 'official_source_direct', 'Applies exclusively to candidates for judicial office.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('0f9d50e25aaf4f50', 'LA', '["judicial"]', 'voter_interaction', 'Can a judicial candidate promise to be ''tough on crime'' if elected?', '["Judicial campaign promises","What can a judge say during a campaign?","Pledges by judicial candidates"]', 'No. The Code of Judicial Conduct strictly prohibits a candidate from making pledges, promises, or commitments that are inconsistent with the impartial performance of the adjudicative duties of the office.', 'https://www.lasc.org/rules/supreme/cjc.asp', 'Louisiana Supreme Court – Code of Judicial Conduct Canon 7', '2026-05-09', 'static', 'official_source_direct', 'Applies exclusively to candidates for judicial office.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('4e4cb0ca836fd739', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'Are campaign signs allowed to be placed on state highway rights-of-way?', '["Can I put signs in the median?","Highway campaign sign rules","Does the state take down political signs?"]', 'No. Louisiana law strictly prohibits the placement of unauthorized signs, including political campaign signs, on any state highway right-of-way. The Department of Transportation is authorized to immediately remove them.', 'https://www.legis.la.gov/Legis/Law.aspx?d=102832', 'Louisiana Revised Statutes § 48:347', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates placing campaign signage.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('2e2051abff9ba3ff', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'Does the state have a deadline for when campaign signs must be taken down after the election?', '["When do I have to remove yard signs?","Post-election signage removal","How long can signs stay up?"]', 'State law bans signs on state property entirely. For private property and local rights-of-way, sign size limits and removal deadlines (often 30 days post-election) are governed strictly by local parish or municipal ordinances.', 'https://www.legis.la.gov/Legis/Law.aspx?d=102832', 'Louisiana Revised Statutes § 48:347 (Context)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns conducting field operations.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('806be6605849a562', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Does a robocall from my campaign require a specific disclaimer?', '["Robocall rules","Voice call political advertising","Do auto-dialers need to say who paid for it?"]', 'Yes. Any automated or live telephone call supporting or opposing a candidate must clearly identify the person or organization paying for the call.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81308', 'Louisiana Revised Statutes § 18:1463', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns conducting phone outreach.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('948a9433c1583325', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Do SMS text messages require a ''Paid for by'' political disclaimer?', '["Text messaging campaign rules","Do campaign texts need disclaimers?","Mass texting disclosure"]', 'Yes. The Louisiana Board of Ethics has determined that SMS text messages fall under the purview of political advertising laws (R.S. 18:1463) and must include the ''Paid for by'' disclaimer within the message or via a prominent link.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81308', 'Louisiana Revised Statutes § 18:1463', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns using mass SMS.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('f6f46b9c73cc76fa', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'Are there specific rules for ''push polling'' in Louisiana?', '["Push poll disclosure","Negative survey rules","Is it legal to poll with negative information?"]', 'Yes. If a campaign or PAC conducts a push poll (a survey meant to persuade rather than gather data), the caller must state the name of the organization paying for the poll at the beginning of the call.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81309', 'Louisiana Revised Statutes § 18:1463.1', '2026-05-09', 'static', 'statute_citation', 'Applies to all organizations conducting political phone surveys.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('d8d04e51342a7abc', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'If my campaign coordinates with a PAC on an advertisement, is it still an ''Independent Expenditure''?', '["PAC coordination rules","What if a super PAC talks to me?","Coordinated spending definition"]', 'No. If an expenditure is coordinated with, made with the cooperation of, or made at the request of a candidate, it is legally considered an ''in-kind'' contribution to the campaign and is strictly subject to contribution limits.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns interacting with outside PACs.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('66898659ba54c076', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Does a PAC have to report independent expenditures that advocate for me?', '["Reporting independent money","Do third parties have to disclose spending?","IE reporting threshold"]', 'Yes. Any person or PAC making independent expenditures aggregating in excess of $500 to support or oppose a candidate must file a report with the Board of Ethics.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81289', 'Louisiana Revised Statutes § 18:1501.1', '2026-05-09', 'static', 'statute_citation', 'Applies to third-party entities funding political ads.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('98229934c0614ce5', 'LA', '["state","parish","municipal","special_district"]', 'finance_ethics', 'Does the Open Meetings Law apply to un-elected candidates having strategy meetings?', '["Sunshine law for candidates","Can candidates talk in private?","Does the public records law apply before I win?"]', 'Generally, no. Private candidates are not considered a public body. However, if a candidate is interacting with a quorum of an already established public board regarding public business, it may trigger an Open Meetings violation for the incumbents.', 'https://www.legis.la.gov/Legis/Law.aspx?d=99525', 'Louisiana Revised Statutes § 42:11', '2026-05-09', 'static', 'statute_citation', 'Applies to candidate interactions with established boards.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('0f08f59c203c7112', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'filing_requirements', 'Do out-of-state political consultants have to register with the state?', '["Consultant registration requirements","Hiring DC consultants","Do campaign vendors need a state license?"]', 'Louisiana does not have a specific ''campaign consultant'' registry. However, any out-of-state business entity (LLC, Corporation) conducting sustained business within Louisiana must register with the Secretary of State as a foreign business entity.', 'https://www.sos.la.gov/BusinessServices/FileBusinessDocuments/Pages/default.aspx', 'Louisiana Secretary of State – Commercial Division', '2026-05-09', 'static', 'official_source_direct', 'Applies to out-of-state campaign vendors.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('45c9a7b27abca9dc', 'LA', '["state"]', 'finance_ethics', 'If I am a registered lobbyist, can I still run for state office?', '["Lobbyist running for legislature","Can I lobby while campaigning?","Restrictions on lobbying candidates"]', 'Yes, but there are severe restrictions. The Louisiana Ethics Code prohibits registered lobbyists from serving on certain boards or making campaign contributions to legislative/executive branch officials they are registered to lobby.', 'http://ethics.la.gov/Pub/Laws/LobbyistLaws.pdf', 'Louisiana Board of Ethics – Lobbying Laws', '2026-05-09', 'static', 'official_source_direct', 'Applies to registered lobbyists seeking office.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('6a72e76b65aa30bc', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'What must I do with my surplus campaign funds after the election?', '["Disposing of leftover money","Can I keep my campaign cash?","Final campaign account closure"]', 'Surplus funds may be returned pro-rata to contributors, donated to a tax-exempt charitable organization, given to a recognized political party, or retained in the campaign account for a future election.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2(I)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates concluding an election cycle.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('7a2af637319f7e86', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Can I transfer leftover funds from my city council race to a new campaign for State Senate?', '["Transferring funds between offices","Rolling over money to a new race","Using local money for a state run"]', 'Yes. Louisiana law allows you to retain campaign funds and transfer them for use in a future campaign for the same office or a completely different office, provided the transfer doesn''t violate contribution limits.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2(I)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates shifting offices between cycles.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('34007e1186344ba2', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Does Louisiana require me to open a separate ''Officeholder Account'' after I win?', '["Officeholder account rules","Do I need a new bank account once elected?","Keeping the campaign account open"]', 'No. Unlike Florida, Louisiana does not require a distinct separate bank account called an ''officeholder account.'' An elected official simply uses their existing campaign account to pay for expenses ''related to the holding of public office.''', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2(I)', '2026-05-09', 'static', 'statute_citation', 'Applies to successful candidates transitioning to officeholders.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('b702ca1b107b79f9', 'LA', '["state"]', 'finance_ethics', 'Can a state legislator raise money during the legislative session?', '["Legislative blackout period","Fundraising during session","Can I take donations while the legislature is meeting?"]', 'No. Louisiana enforces a strict ''blackout'' period. Legislators and candidates for the legislature are prohibited from soliciting or receiving campaign contributions during any regular legislative session.', 'https://www.legis.la.gov/legis/Law.aspx?d=81313', 'Louisiana Revised Statutes § 18:1505.2(S)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for the State House and State Senate.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('4c0f3f37447dcaa5', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to report a loan from a bank to my campaign differently than a personal loan?', '["Reporting bank loans","Are commercial loans subject to limits?","How to disclose campaign debt"]', 'Yes. A loan from a commercial lending institution made in the ordinary course of business is not considered a contribution subject to limits, but it MUST be reported as a loan on the campaign finance report.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81274', 'Louisiana Revised Statutes § 18:1491.3', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns utilizing bank financing.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('f74e6eae30e9fc14', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'Can I pay someone to vote for me?', '["Is vote buying illegal?","Offering money for a vote","Bribery rules"]', 'No. Under Louisiana law, it is a criminal offense to give, offer, or promise anything of present or prospective value to any person to influence their vote.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81421', 'Louisiana Revised Statutes § 18:1461.2', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns and individuals.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('2bda78d70c5dc93d', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'voter_interaction', 'What constitutes voter intimidation in Louisiana?', '["Can supporters yell at voters?","Voter intimidation laws","Threatening voters at the polls"]', 'It is a criminal offense to use intimidation, force, or coercion to influence a voter or to compel them to vote or refrain from voting for any specific candidate.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81421', 'Louisiana Revised Statutes § 18:1461.4', '2026-05-09', 'static', 'statute_citation', 'Applies to all individuals engaging with voters.', 'batch_2026-05-10T02-10-04_louisiana_full_v1'),
  ('9ec3cdbf504ba048', 'LA', '["federal","state","parish","municipal","judicial","special_district"]', 'finance_ethics', 'When is a campaign finance report legally considered ''filed''?', '["Does the postmark count as the filing date?","When is the disclosure deadline?","Electronic submission timing"]', 'For paper filings (if permitted), the report is deemed filed on the date it is postmarked by the USPS. For electronic filings, it is considered filed at the exact date and time it is successfully transmitted to the Board of Ethics portal.', 'https://www.legis.la.gov/Legis/Law.aspx?d=81267', 'Louisiana Revised Statutes § 18:1485', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates submitting required reports.', 'batch_2026-05-10T02-10-04_louisiana_full_v1')
